374→func readSettings(path string) (map[string]json.RawMessage, error) {
375→	data, err := os.ReadFile(path)
376→	if err != nil {
377→		if os.IsNotExist(err) {
378→			return map[string]json.RawMessage{}, nil
379→		}
380→		return nil, err
381→	}
382→	var settings map[string]json.RawMessage
383→	if err := json.Unmarshal(data, &settings); err != nil {
384→		return nil, err
385→	}
386→	if settings == nil {
387→		settings = map[string]json.RawMessage{}
388→	}
389→	return settings, nil
390→}
391→
392→func readTrustedCommands(settings map[string]json.RawMessage) ([]string, error) {
393→	raw, ok := settings[trustedCommandsKey]
394→	if !ok {
395→		return []string{}, nil
396→	}
397→	var commands []string
398→	if err := json.Unmarshal(raw, &commands); err != nil {
399→		return nil, err
400→	}
401→	return commands, nil
402→}
403→
404→func writeSettings(path string, settings map[string]json.RawMessage) error {
405→	if err := os.MkdirAll(filepath.Dir(path), 0o750); err != nil {
406→		return err
407→	}
408→	data, err := marshalJSON(settings)
409→	if err != nil {
410→		return err
411→	}
412→	return os.WriteFile(path, data, 0o600)
413→}
414→
415→func marshalJSON(v any) ([]byte, error) {
416→	data, err := json.MarshalIndent(v, "", "  ")
417→	if err != nil {
418→		return nil, err
419→	}
420→	return append(data, '\n'), nil
421→}
422→
423→func isEntireIDEHook(hook kiroIDEHookFile) bool {
424→	return strings.HasPrefix(hook.Name, "entire-") && strings.HasPrefix(hook.Then.Command, prodHookCommandBase)
425→}
426→
427→func (a *Agent) generateAndCacheSessionID() string {
428→	sessionID := generateSessionID()
429→	cachePath := a.sessionIDCachePath()
430→	if err := os.MkdirAll(filepath.Dir(cachePath), 0o750); err == nil {
431→		_ = os.WriteFile(cachePath, []byte(sessionID), 0o600)
432→	}
433→	return sessionID
434→}
435→
436→func (a *Agent) readCachedSessionID() string {
437→	data, err := os.ReadFile(a.sessionIDCachePath())
438→	if err != nil {
439→		return ""
440→	}
441→	return strings.TrimSpace(string(data))
442→}
443→
444→func (a *Agent) clearCachedSessionID() {
445→	_ = os.Remove(a.sessionIDCachePath())
446→}
447→
448→func (a *Agent) sessionIDCachePath() string {
449→	return filepath.Join(protocol.RepoRoot(), ".entire", "tmp", sessionIDFile)
450→}
451→
452→func fallbackStopSessionID() string {
453→	return generateSessionID()
454→}
455→
456→func generateSessionID() string {
457→	buf := make([]byte, 16)
458→	if _, err := rand.Read(buf); err != nil {
459→		return fmt.Sprintf("kiro-%d", time.Now().UnixNano())
460→	}
461→	return hex.EncodeToString(buf)
462→}
