266→// ForEachAgent runs fn as a parallel subtest for every registered agent.
267→// It handles repo setup, concurrency gating, context timeout, and cleanup.
268→// The timeout is scaled by each agent's TimeoutMultiplier.
269→//
270→// If RunPrompt detects a transient API error (e.g. rate limit, token refresh
271→// failure), it panics with errScenarioRestart. ForEachAgent recovers from the
272→// panic and restarts the entire scenario with a fresh repository, up to
273→// maxScenarioRestarts times. This avoids stale CLI session state from the
274→// failed attempt poisoning the retry.
275→func ForEachAgent(t *testing.T, timeout time.Duration, fn func(t *testing.T, s *RepoState, ctx context.Context)) {
276→	t.Helper()
277→	t.Parallel()
278→	all := agents.All()
279→	if len(all) == 0 {
280→		t.Skip("no agents registered (check E2E_AGENT filter)")
281→	}
282→	for _, agent := range all {
283→		t.Run(agent.Name(), func(t *testing.T) {
284→			// Use the global test deadline for slot wait so we don't
285→			// skip prematurely — only bail if the whole binary is dying.
286→			slotCtx := context.Background()
287→			if deadline, ok := t.Deadline(); ok {
288→				var cancel context.CancelFunc
289→				slotCtx, cancel = context.WithDeadline(slotCtx, deadline)
290→				defer cancel()
291→			}
292→			if err := agents.AcquireSlot(slotCtx, agent); err != nil {
293→				t.Fatalf("timed out waiting for agent slot: %v", err)
294→			}
295→			defer agents.ReleaseSlot(agent)
296→
297→			// Per-test timeout starts after slot is acquired, scaled
298→			// by the agent's multiplier (e.g. 2.5× for gemini).
299→			scaled := time.Duration(float64(timeout) * agent.TimeoutMultiplier())
300→
301→			var prevState *RepoState
302→			for attempt := range maxScenarioRestarts + 1 {
303→				s := SetupRepo(t, agent)
304→				ctx, cancel := context.WithTimeout(context.Background(), scaled)
305→
306→				// On restart, suppress artifact capture from the previous
307→				// failed attempt so it doesn't overwrite the final one.
308→				if prevState != nil {
309→					prevState.skipArtifacts = true
310→				}
311→
312→				restarted := runScenario(t, s, ctx, fn)
313→				cancel()
314→
315→				if !restarted {
316→					return
317→				}
318→				prevState = s
319→				if attempt >= maxScenarioRestarts {
320→					t.Fatalf("exhausted %d scenario attempts due to transient API errors", maxScenarioRestarts+1)
321→				}
322→				t.Logf("transient error, restarting scenario (attempt %d/%d)", attempt+2, maxScenarioRestarts+1)
323→			}
324→		})
325→	}
326→}
327→
328→// runScenario runs the test function and recovers from errScenarioRestart
329→// panics triggered by transient API errors in RunPrompt. Returns true if
330→// the scenario should be restarted with a fresh repository.
331→func runScenario(t *testing.T, s *RepoState, ctx context.Context, fn func(t *testing.T, s *RepoState, ctx context.Context)) (restarted bool) {
332→	t.Helper()
333→	defer func() {
334→		if r := recover(); r != nil {
335→			if _, ok := r.(errScenarioRestart); ok {
336→				restarted = true
337→				return
338→			}
339→			panic(r) // re-panic for unexpected panics
340→		}
341→	}()
342→	fn(t, s, ctx)
343→	return false
344→}
345→
346→const maxScenarioRestarts = 2 // restart up to 2 times = 3 total attempts
347→
348→// errScenarioRestart is panicked by RunPrompt when a transient API error is
349→// detected. ForEachAgent recovers from this panic and restarts the test
350→// scenario with a fresh repository, avoiding stale CLI state from the failed
351→// attempt.
352→type errScenarioRestart struct {
353→	msg string
354→}
355→
356→// RunPrompt runs an agent prompt, logs the command and output to ConsoleLog,
357→// and returns the result. If the agent reports a transient API error, it
358→// panics with errScenarioRestart to trigger a full scenario restart in
359→// ForEachAgent (see runScenario).
360→func (s *RepoState) RunPrompt(t *testing.T, ctx context.Context, prompt string, opts ...agents.Option) (agents.Output, error) {
361→	t.Helper()
362→	out, err := s.Agent.RunPrompt(ctx, s.Dir, prompt, opts...)
363→	s.logPromptResult(out)
364→
365→	if err != nil && s.Agent.IsTransientError(out, err) {
366→		errMsg := fmt.Sprintf("transient API error (stderr: %s)", strings.TrimSpace(out.Stderr))
367→		t.Logf("%s — restarting scenario", errMsg)
368→		fmt.Fprintf(s.ConsoleLog, "> [transient] %s — restarting scenario\n", errMsg)
369→		panic(errScenarioRestart{msg: errMsg})
370→	}
371→
372→	return out, err
373→}
374→
375→func (s *RepoState) logPromptResult(out agents.Output) {
376→	s.ConsoleLog.WriteString("> " + out.Command + "\n")
377→	s.ConsoleLog.WriteString("stdout:\n" + out.Stdout + "\n")
378→	s.ConsoleLog.WriteString("stderr:\n" + out.Stderr + "\n")
379→}
380→
381→// Git runs a git command in the repo and logs it to ConsoleLog.
382→func (s *RepoState) Git(t *testing.T, args ...string) {
383→	t.Helper()
384→	s.ConsoleLog.WriteString("> git " + strings.Join(args, " ") + "\n")
385→	Git(t, s.Dir, args...)
386→}
387→
388→// StartSession starts an interactive session and registers it for pane
389→// capture in artifacts. Returns nil if the agent does not support interactive
390→// mode. The session is closed automatically during test cleanup.
391→func (s *RepoState) StartSession(t *testing.T, ctx context.Context) agents.Session {
392→	t.Helper()
393→	session, err := s.Agent.StartSession(ctx, s.Dir)
394→	if err != nil {
395→		t.Fatalf("start session: %v", err)
396→	}
397→	if session == nil {
398→		return nil
399→	}
400→	s.session = session
401→	return session
402→}
