404→// WaitFor waits for a pattern in the interactive session's pane and logs the
405→// pane content to ConsoleLog after the wait completes (success or failure).
406→func (s *RepoState) WaitFor(t *testing.T, session agents.Session, pattern string, timeout time.Duration) {
407→	t.Helper()
408→	content, err := session.WaitFor(pattern, timeout)
409→	fmt.Fprintf(s.ConsoleLog, "> pane after WaitFor(%q):\n%s\n", pattern, content)
410→	if err != nil {
411→		t.Fatalf("WaitFor(%q): %v", pattern, err)
412→	}
413→}
