543→	var meta CheckpointMetadata
544→	if err := json.Unmarshal([]byte(raw), &meta); err != nil {
545→		t.Fatalf("unmarshal checkpoint metadata from %s: %v", blob, err)
546→	}
547→
548→	return meta
549→}
