239→// WaitForSessionIdle polls the session state files in .git/entire-sessions/
240→// until no session has phase "active", or fails the test after timeout.
241→// This handles the race where an agent's prompt pattern appears in the TUI
242→// before the turn-end hook has completed (transitioning ACTIVE → IDLE).
243→func WaitForSessionIdle(t *testing.T, dir string, timeout time.Duration) {
244→	t.Helper()
245→	stateDir := filepath.Join(dir, ".git", "entire-sessions")
246→	deadline := time.Now().Add(timeout)
247→	for time.Now().Before(deadline) {
248→		entries, err := os.ReadDir(stateDir)
249→		if err != nil {
250→			// Directory may not exist yet; keep polling
251→			time.Sleep(200 * time.Millisecond)
252→			continue
253→		}
254→		anyActive := false
255→		for _, entry := range entries {
256→			if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".json") || strings.HasSuffix(entry.Name(), ".tmp") {
257→				continue
258→			}
259→			data, err := os.ReadFile(filepath.Join(stateDir, entry.Name()))
260→			if err != nil {
261→				continue
262→			}
263→			var state struct {
264→				Phase string `json:"phase"`
265→			}
266→			if err := json.Unmarshal(data, &state); err != nil {
267→				continue
268→			}
269→			if state.Phase == "active" {
270→				anyActive = true
271→				break
272→			}
273→		}
274→		if !anyActive {
275→			return
276→		}
277→		time.Sleep(200 * time.Millisecond)
278→	}
279→	t.Fatalf("session(s) did not transition to idle within %s", timeout)
280→}
