319→// ValidateCheckpointDeep performs comprehensive validation of checkpoint metadata
320→// on the checkpoint branch, including transcript JSONL validity, content hash
321→// verification, and prompt content checking.
322→func ValidateCheckpointDeep(t *testing.T, dir string, v DeepCheckpointValidation) {
323→	t.Helper()
324→
325→	// Basic metadata validation
326→	AssertCheckpointExists(t, dir, v.CheckpointID)
327→	AssertCheckpointMetadataComplete(t, dir, v.CheckpointID)
328→
329→	if v.Strategy != "" {
330→		meta := ReadCheckpointMetadata(t, dir, v.CheckpointID)
331→		assert.Equal(t, v.Strategy, meta.Strategy,
332→			"checkpoint %s: strategy mismatch", v.CheckpointID)
333→	}
334→
335→	if len(v.FilesTouched) > 0 {
336→		AssertCheckpointFilesTouched(t, dir, v.CheckpointID, v.FilesTouched)
337→	}
338→
339→	path := CheckpointPath(v.CheckpointID)
340→
341→	// Validate session metadata exists and has checkpoint_id
342→	sessionBlob := fmt.Sprintf("entire/checkpoints/v1:%s/0/metadata.json", path)
343→	sessionRaw := gitOutputSafe(dir, "show", sessionBlob)
344→	if assert.NotEmpty(t, sessionRaw, "session metadata should exist at %s", sessionBlob) {
345→		var sessionMeta map[string]any
346→		if assert.NoError(t, json.Unmarshal([]byte(sessionRaw), &sessionMeta)) {
347→			assert.Equal(t, v.CheckpointID, sessionMeta["checkpoint_id"],
348→				"session metadata checkpoint_id should match")
349→			assert.NotEmpty(t, sessionMeta["created_at"], "session metadata should have created_at")
350→		}
351→	}
352→
353→	// Validate transcript is valid JSONL
354→	transcriptBlob := fmt.Sprintf("entire/checkpoints/v1:%s/0/full.jsonl", path)
355→	transcriptRaw := gitOutputSafe(dir, "show", transcriptBlob)
356→	if assert.NotEmpty(t, transcriptRaw, "transcript should exist at %s", transcriptBlob) {
357→		lines := strings.Split(transcriptRaw, "\n")
358→		nonEmpty := 0
359→		for _, line := range lines {
360→			if strings.TrimSpace(line) != "" {
361→				nonEmpty++
362→			}
363→		}
364→		assert.Positive(t, nonEmpty, "transcript should have at least one line")
365→
366→		for _, expected := range v.ExpectedTranscriptContent {
367→			assert.Contains(t, transcriptRaw, expected,
368→				"transcript should contain %q", expected)
369→		}
370→
371→		// Validate content hash
372→		hashBlob := fmt.Sprintf("entire/checkpoints/v1:%s/0/content_hash.txt", path)
373→		hashRaw := gitOutputSafe(dir, "show", hashBlob)
374→		if hashRaw != "" {
375→			hash := sha256.Sum256([]byte(transcriptRaw))
376→			expectedHash := "sha256:" + hex.EncodeToString(hash[:])
377→			assert.Equal(t, expectedHash, strings.TrimSpace(hashRaw),
378→				"content hash should match transcript SHA-256")
379→		}
380→	}
381→
382→	// Validate prompt.txt if expected prompts specified
383→	if len(v.ExpectedPrompts) > 0 {
384→		promptBlob := fmt.Sprintf("entire/checkpoints/v1:%s/0/prompt.txt", path)
385→		promptRaw := gitOutputSafe(dir, "show", promptBlob)
386→		for _, expected := range v.ExpectedPrompts {
387→			assert.Contains(t, promptRaw, expected,
388→				"prompt.txt should contain %q", expected)
389→		}
390→	}
391→}
