  1→package main
  2→
  3→import (
  4→	"bufio"
  5→	"bytes"
  6→	"encoding/json"
  7→	"fmt"
  8→	"os"
  9→	"os/exec"
 10→	"path/filepath"
 11→	"regexp"
 12→	"strings"
 13→
 14→	"github.com/google/uuid"
 15→)
 16→
 17→func main() {
 18→	dir, err := os.Getwd()
 19→	if err != nil {
 20→		fatal("getwd: %v", err)
 21→	}
 22→
 23→	sessionID := uuid.New().String()
 24→	transcriptPath := setupTranscript(sessionID)
 25→
 26→	fireHook(dir, "session-start", map[string]string{
 27→		"session_id":      sessionID,
 28→		"transcript_path": transcriptPath,
 29→	})
 30→
 31→	fmt.Fprint(os.Stdout, "> ")
 32→	scanner := bufio.NewScanner(os.Stdin)
 33→	for scanner.Scan() {
 34→		line := strings.TrimSpace(scanner.Text())
 35→		if line == "" || line == "exit" || line == "quit" {
 36→			break
 37→		}
 38→		runTurn(dir, sessionID, transcriptPath, line)
 39→		fmt.Fprint(os.Stdout, "> ")
 40→	}
 41→
 42→	fireHook(dir, "session-end", map[string]string{
 43→		"session_id":      sessionID,
 44→		"transcript_path": transcriptPath,
 45→	})
 46→}
 47→
 48→func runTurn(dir, sessionID, transcriptPath, prompt string) {
 49→	fireHook(dir, "user-prompt-submit", map[string]any{
 50→		"session_id":      sessionID,
 51→		"transcript_path": transcriptPath,
 52→		"prompt":          prompt,
 53→	})
 54→
 55→	appendTranscript(transcriptPath, "user", prompt)
 56→
 57→	response := handlePrompt(dir, prompt)
 58→
 59→	appendTranscript(transcriptPath, "assistant", response)
 60→	fmt.Fprintln(os.Stdout, response)
 61→
 62→	fireHook(dir, "stop", map[string]string{
 63→		"session_id":      sessionID,
 64→		"transcript_path": transcriptPath,
 65→	})
 66→}
 67→
 68→// --- Prompt Handling ---
 69→
 70→var createFileRe = regexp.MustCompile(`(?i)create\s+(?:a\s+)?(?:\w+\s+)*?file\s+(?:at\s+|called\s+)?([^\s,]+\.\w+)`)
 71→
 72→func handlePrompt(dir, prompt string) string {
 73→	if m := createFileRe.FindStringSubmatch(prompt); m != nil {
 74→		path := m[1]
 75→		createFile(dir, path, fmt.Sprintf("# %s\n", path))
 76→		return fmt.Sprintf("Created %s.", path)
 77→	}
 78→	return "roger roger"
 79→}
 80→
 81→func createFile(dir, path, content string) {
 82→	abs := filepath.Join(dir, path)
 83→	if err := os.MkdirAll(filepath.Dir(abs), 0o755); err != nil {
 84→		fmt.Fprintf(os.Stderr, "mkdir %s: %v\n", filepath.Dir(abs), err)
 85→		return
 86→	}
 87→	if err := os.WriteFile(abs, []byte(content), 0o644); err != nil {
 88→		fmt.Fprintf(os.Stderr, "write %s: %v\n", abs, err)
 89→	}
 90→}
 91→
 92→// --- Hook Firing ---
 93→
 94→func fireHook(dir, hookName string, payload any) {
 95→	data, err := json.Marshal(payload)
 96→	if err != nil {
 97→		return
 98→	}
 99→	cmd := exec.Command("entire", "hooks", "roger-roger", hookName)
100→	cmd.Dir = dir
101→	cmd.Stdin = bytes.NewReader(data)
102→	cmd.Env = append(os.Environ(), "ENTIRE_TEST_TTY=0")
103→	cmd.CombinedOutput()
104→}
105→
106→// --- Transcript ---
107→
108→// transcriptLine matches the standard JSONL transcript format used by Claude Code / Cursor.
109→// The "message" field is a raw JSON object whose structure depends on the "type".
110→type transcriptLine struct {
111→	Type    string          `json:"type"`
112→	UUID    string          `json:"uuid"`
113→	Message json.RawMessage `json:"message"`
114→}
115→
116→type userMessage struct {
117→	Content string `json:"content"`
118→}
119→
120→type assistantMessage struct {
121→	Content []contentBlock `json:"content"`
122→}
123→
124→type contentBlock struct {
125→	Type string `json:"type"`
126→	Text string `json:"text,omitempty"`
127→}
128→
129→func setupTranscript(sessionID string) string {
130→	home, err := os.UserHomeDir()
131→	if err != nil {
132→		fatal("home dir: %v", err)
133→	}
134→	transcriptDir := filepath.Join(home, ".roger-roger", "sessions")
135→	if err := os.MkdirAll(transcriptDir, 0o755); err != nil {
136→		fatal("mkdir transcript dir: %v", err)
137→	}
138→	path := filepath.Join(transcriptDir, sessionID+".jsonl")
139→	if err := os.WriteFile(path, nil, 0o644); err != nil {
140→		fatal("create transcript: %v", err)
141→	}
142→	return path
143→}
144→
145→func appendTranscript(path, role, content string) {
146→	var msg json.RawMessage
147→	switch role {
148→	case "user":
149→		msg, _ = json.Marshal(userMessage{Content: content})
150→	case "assistant":
151→		msg, _ = json.Marshal(assistantMessage{
152→			Content: []contentBlock{{Type: "text", Text: content}},
153→		})
154→	}
155→
156→	entry := transcriptLine{
157→		Type:    role,
158→		UUID:    uuid.New().String(),
159→		Message: msg,
160→	}
161→	data, _ := json.Marshal(entry)
162→	data = append(data, '\n')
163→	f, err := os.OpenFile(path, os.O_APPEND|os.O_WRONLY|os.O_CREATE, 0o644)
164→	if err != nil {
165→		return
166→	}
167→	defer f.Close()
168→	f.Write(data)
169→}
170→
171→func fatal(format string, args ...any) {
172→	fmt.Fprintf(os.Stderr, "roger-roger: "+format+"\n", args...)
173→	os.Exit(1)
174→}
