269→func cmdParseHook() {
270→	hookName := getFlag("--hook")
271→	data, err := io.ReadAll(os.Stdin)
272→	if err != nil {
273→		fatal("read stdin: %v", err)
274→	}
275→
276→	var raw struct {
277→		SessionID      string `json:"session_id"`
278→		TranscriptPath string `json:"transcript_path"`
279→		Prompt         string `json:"prompt"`
280→	}
281→	if err := json.Unmarshal(data, &raw); err != nil {
282→		fatal("parse hook input: %v", err)
283→	}
284→
285→	ts := time.Now().Format(time.RFC3339)
286→	var eventType int
287→	switch hookName {
288→	case "session-start":
289→		eventType = eventSessionStart
290→	case "user-prompt-submit":
291→		eventType = eventTurnStart
