495→func chunkJSONL(data []byte, maxSize int) [][]byte {
496→	if len(data) == 0 {
497→		return nil
498→	}
499→	if maxSize <= 0 || len(data) <= maxSize {
500→		return [][]byte{data}
501→	}
502→	var chunks [][]byte
503→	var current []byte
504→	for _, line := range bytes.Split(data, []byte("\n")) {
505→		if len(line) == 0 {
506→			continue
507→		}
508→		lineWithNewline := append(line, '\n')
509→		if len(current)+len(lineWithNewline) > maxSize && len(current) > 0 {
510→			chunks = append(chunks, current)
511→			current = nil
512→		}
513→		current = append(current, lineWithNewline...)
514→	}
515→	if len(current) > 0 {
516→		chunks = append(chunks, current)
517→	}
518→	return chunks
519→}
